// src/views/user/MyProfile/composables/useModules.js
import { ref } from 'vue'
import profile from '@/api/profile'
import { ALL_MODULES } from '@/constants'

export function useModules() {
  const loading = ref(false)
  const activeModules = ref([])
  const inactiveModules = ref([])

  // 获取模块数据
  const fetchModulesData = async () => {
    try {
      loading.value = true
      const response = await profile.layout.update()
      console.log('【模块数据】开始获取布局数据:', response.data)

      if (response?.data?.code === 200) {
        const layoutData = response.data.data.layout

        // 获取各模块数据
        const moduleDataPromises = []

        // 获取所有可见模块的数据
        for (const [type, config] of Object.entries(layoutData)) {
          if (config.visible) {
            switch (type) {
              case 'education':
                moduleDataPromises.push(
                  profile.education.get()
                    .then(response => ({
                      type,
                      data: response.data?.code === 200 ? response.data.data : [],
                      name: ALL_MODULES[type]
                    }))
                    .catch(error => {
                      console.error('获取教育经历数据失败:', error)
                      return { type, data: [], name: ALL_MODULES[type] }
                    })
                )
                break

              case 'job_intention':
                moduleDataPromises.push(
                  profile.jobIntention.get()
                    .then(response => ({
                      type,
                      data: response.data?.code === 200 ? response.data.data : null,
                      name: ALL_MODULES[type]
                    }))
                    .catch(error => {
                      console.error('获取求职意向数据失败:', error)
                      return { type, data: null, name: ALL_MODULES[type] }
                    })
                )
                break

              case 'work_experience':
                moduleDataPromises.push(
                  profile.workExperience.get()
                    .then(response => ({
                      type,
                      data: response.data?.code === 200 ? response.data.data : [],
                      name: ALL_MODULES[type]
                    }))
                    .catch(error => {
                      console.error('获取工作经历数据失败:', error)
                      return { type, data: [], name: ALL_MODULES[type] }
                    })
                )
                break
            }
          }
        }

        // 等待所有数据获取完成
        const modulesData = await Promise.all(moduleDataPromises)
        console.log('【模块数据】所有模块数据获取完成:', modulesData)

        // 更新模块数据
        activeModules.value = modulesData
          .filter(module => layoutData[module.type]?.visible)
          .sort((a, b) => layoutData[a.type].order - layoutData[b.type].order)

        // 更新未激活模块列表
        inactiveModules.value = Object.entries(ALL_MODULES)
          .filter(([type]) => !activeModules.value.some(m => m.type === type))
          .map(([type, name]) => ({
            type,
            name
          }))

        console.log('【模块数据】更新后的活动模块:', activeModules.value)
        console.log('【模块数据】未激活模块:', inactiveModules.value)
      }
    } catch (error) {
      console.error('【模块数据】获取失败:', error)
    } finally {
      loading.value = false
    }
  }

  // 添加模块（激活模块）
  const addModule = async (moduleType) => {
    try {
      loading.value = true
      console.log('【模块数据】准备激活模块:', moduleType)

      // 获取当前所有可见模块的配置
      const visibleModules = {}
      activeModules.value.forEach((module, index) => {
        visibleModules[module.type] = {
          visible: true,
          order: index + 1  // 保持现有模块的顺序
        }
      })

      // 添加新模块到最后
      const layoutUpdate = {
        ...visibleModules,  // 保持现有模块的配置
        [moduleType]: {
          visible: true,
          order: activeModules.value.length + 1  // 新模块放在最后
        }
      }

      console.log('【模块数据】更新布局:', layoutUpdate)
      const response = await profile.layout.update(layoutUpdate)
      console.log('【模块数据】服务器返回的更新结果:', response.data)

      if (response?.data?.code === 200) {
        await fetchModulesData()
      }
    } catch (error) {
      console.error('激活模块失败:', error)
    } finally {
      loading.value = false
    }
  }

  // 移除模块（取消激活）
  const removeModule = async (moduleType) => {
    try {
      loading.value = true
      console.log('【模块数据】准备取消激活模块:', moduleType)

      // 获取当前所有模块的配置（除了要移除的）
      const updatedModules = {}
      activeModules.value
        .filter(module => module.type !== moduleType)
        .forEach((module, index) => {
          updatedModules[module.type] = {
            visible: true,
            order: index + 1  // 重新排序剩余模块
          }
        })

      // 添加要移除的模块配置
      const layoutUpdate = {
        ...updatedModules,
        [moduleType]: {
          visible: false,
          order: 999  // 移到未激活模块区域
        }
      }

      console.log('【模块数据】更新布局:', layoutUpdate)
      const response = await profile.layout.update(layoutUpdate)
      console.log('【模块数据】服务器返回的更新结果:', response.data)

      if (response?.data?.code === 200) {
        await fetchModulesData()
      }
    } catch (error) {
      console.error('取消激活模块失败:', error)
    } finally {
      loading.value = false
    }
  }

  return {
    loading,
    activeModules,
    inactiveModules,
    fetchModulesData,
    addModule,     // 确保导出这两个方法
    removeModule
  }
}
